class Solution:
    def isValidSerialization(self, preorder: str) -> bool:
        tokens = preorder.split(',')
        idx = 0
        def parse():
            nonlocal idx
            if idx >= len(tokens):
                return False
            t = tokens[idx]
            idx += 1
            if t == '#':
                return True
            return parse() and parse()
        ok = parse()
        return ok and idx == len(tokens)

